export function getManufacturers(): string[] {
  return [...new Set(IOL_CATALOG.map((l) => l.manufacturer))].sort()
}

export function getLensesByManufacturer(mfr: string): IOL[] {
  return IOL_CATALOG.filter((l) => l.manufacturer === mfr)
}

